export async function seed() {
  console.log("Seeding products...");
  let inserted = 0;
  for (let i = 0; i < PRODUCTS.length; i++) {
    const p = PRODUCTS[i];
    try {
      const existing = await db.select({ id: productsTable.id }).from(productsTable).where(eq(productsTable.slug, p.slug));
      if (existing.length === 0) {
        await db.insert(productsTable).values({ ...p, sortOrder: i, visible: true });
        inserted++;
      }
    } catch (err) {
      console.error(`Error inserting ${p.slug}:`, err);
    }
  }
  console.log(`Products: ${inserted} inserted, ${PRODUCTS.length - inserted} skipped (already exist)`);

  console.log("Seeding site content...");
  let scInserted = 0;
  for (const entry of BIZ_DEFAULTS) {
    try {
      const existing = await db.select({ id: siteContentTable.id }).from(siteContentTable).where(eq(siteContentTable.key, entry.key));
      if (existing.length === 0) {
        await db.insert(siteContentTable).values(entry);
        scInserted++;
      }
    } catch (err) {
      console.error(`Error inserting site content ${entry.key}:`, err);
    }
  }
  console.log(`Site content: ${scInserted} inserted`);
  console.log("Seed complete.");
}

seed().then(() => process.exit(0)).catch((err) => { console.error(err); process.exit(1); });
